const item = $input.first();
const data = item.json ?? {};
const headers = data.headers ?? {};
const body = data.body ?? data;

const getHeader = (name) => headers[name] ?? headers[name.toLowerCase()] ?? headers[name.toUpperCase()] ?? null;

const token = getHeader('x-clawbot-token');
const environment = getHeader('x-clawbot-environment');
const allowedActions = ['propose_source', 'report_incident', 'summarize_status', 'validate_site'];

const action = body.action ?? null;
const sourceType = body.sourceType ?? null;
const confidence = body.confidence;

let accepted = true;
let httpStatus = 202;
let error = '';

if (!token) {
  accepted = false;
  httpStatus = 401;
  error = 'missing_token';
} else if (environment !== 'staging') {
  accepted = false;
  httpStatus = 403;
  error = 'invalid_environment';
} else if (!action || !sourceType) {
  accepted = false;
  httpStatus = 400;
  error = 'missing_required_fields';
} else if (!allowedActions.includes(action)) {
  accepted = false;
  httpStatus = 400;
  error = 'unsupported_action';
} else if (confidence !== undefined && (typeof confidence !== 'number' || confidence < 0 || confidence > 1)) {
  accepted = false;
  httpStatus = 400;
  error = 'invalid_confidence';
}

return [{ json: { accepted, httpStatus, error, action, sourceType, title: body.title ?? '', summary: body.summary ?? '', url: body.url ?? '', confidence: confidence ?? null, tags: Array.isArray(body.tags) ? body.tags : [], metadata: body.metadata ?? {}, environment: environment ?? null, receivedAt: new Date().toISOString(), rawPayload: body } }];
